parameters.jsCode:
const event = $input.first().json;
const payload = event.payload || event;

const invitee = payload.invitee || {};
const eventInfo = payload.event || {};
const eventType = payload.event_type || {};

if (!invitee.email || !eventInfo.start_time) {
  return [{
    json: {
      parseError: 'Missing invitee email or event start time in Calendly payload',
      raw: payload
    }
  }];
}

return [{
  json: {
    inviteeName: invitee.name || 'Guest',
    inviteeEmail: invitee.email,
    eventType: eventType.name || 'Meeting',
    startTime: eventInfo.start_time,
    endTime: eventInfo.end_time,
    location: eventInfo.location?.join_url || eventInfo.location || 'TBD',
    questions: payload.questions_and_answers || []
  }
}];

